from pathlib import Path
from datetime import datetime
from zoneinfo import ZoneInfo
import json, os

TZ=ZoneInfo('Asia/Shanghai')
now=datetime.now(tz=TZ).replace(microsecond=0)

def iso(dt):
    return dt.isoformat()

def mtime_iso(p: Path):
    ts=p.stat().st_mtime
    return datetime.fromtimestamp(ts, tz=TZ).replace(microsecond=0).isoformat()

# Determine available day dirs and files
week_days=[f'day{d}' for d in range(21,26)]
available=[d for d in week_days if Path(d).exists() and Path(d).is_dir()]
missing=[d for d in week_days if d not in available]

entries=[]
for d in available:
    for p in sorted(Path(d).iterdir()):
        if p.is_file():
            name=p.name
            # classify
            if name in ('sprint9_board.json','delivery_metrics.json'):
                ftype='modified'
                entry={'filename': f'{d}/{name}', 'type': ftype, 'modified_at': mtime_iso(p)}
            else:
                ftype='new'
                entry={'filename': f'{d}/{name}', 'type': ftype, 'created_at': mtime_iso(p)}
            entries.append(entry)

# Also include done.log if present (week-level log)
if Path('done.log').exists():
    entries.append({'filename':'done.log','type':'modified','modified_at':mtime_iso(Path('done.log'))})

out={
  'meta':{
    'created_at': iso(now),
    'author':'metaclaw_agent',
    'scope':'Archive index for Sprint 9 Week 2 (day21-day25)',
    'timezone':'+08:00',
    'available_days': available,
    'missing_days': missing
  },
  'report_generated_at': iso(now),
  'files': entries
}

Path('day25/20260317_archive_index_sprint9_week2.json').write_text(json.dumps(out, indent=2, ensure_ascii=False)+"\n")
print('wrote', 'day25/20260317_archive_index_sprint9_week2.json', 'files', len(entries))
PY
